const PIECES_B = [{"id": "cyber-assurance", "name": "Cyber Assurance", "short": "Cyber Assurance", "icon": "🛡", "color": "#8B3A3A", "blurb": "Security governance, leadership and incident-readiness — not just tools.", "criteria": ["Security tools exist but nobody owns governance, risk decisions or incident readiness", "No documented, tested incident response or business continuity plan", "Regulatory pressure (e.g. NIS2), a customer/insurer ask, or a wish to use security as a competitive differentiator, with nothing formal to show for it"], "implicationQuestions": {"result_mid_tools_gov": "If a serious alert came in tonight, who actually has the authority to decide what happens next?", "result_hot_tools_noplan": "If tools alone were enough, why do so many breaches still happen at businesses with tools in place?", "result_none_governed": "Good — when was that governance model last actually tested against a live scenario?", "result_hot_incident_noplan": "Without a documented plan, how much of that response last time was improvised on the spot?", "result_mid_incident_informal": "If the same incident happened again next month, would the response look any more organised?", "result_warm_noincident": "If an incident did happen tomorrow, who in the business would actually take charge of the response?", "result_hot_noleader_growing": "As the business keeps growing, what's the cost of security decisions continuing to be made without anyone owning them properly?", "result_mid_noleader_adhoc": "When something security-related needs a real decision, who ends up making the call today?", "result_dev_noleader_confident": "If that confidence turned out to be based on assumptions rather than a real review, how would you find out?", "result_hot_compliance_pressure": "What happens to the business relationship if you can't demonstrate that governance when asked?", "result_mid_compliance_unsure": "If a customer or insurer asked for evidence of this tomorrow, could you produce it today?", "result_none_compliance_covered": "Good — is that reviewed on a schedule, or was it done once for a specific deal and left alone?", "result_hot_competitive_newbiz": "How many deals do you reckon have stalled or been lost over this specifically?", "result_dev_competitive_reassure": "If a customer asked and you couldn't answer confidently, what would that do to the relationship?", "result_dev_competitive_ahead": "If a competitor won a deal specifically because they could show this and you couldn't, how would that feel?"}, "needPayoff": {"tools_probe": "If governance and decision-making sat on top of the tools you already have, would that close the gap?", "incident_probe": "If you had a tested plan and a clear owner before the next incident, would that change how confident you feel today?", "noleader_probe": "If you had access to senior security leadership without hiring a full-time executive, would that solve it?", "compliance_probe": "If you could produce clear evidence of governance whenever it's asked for, would that remove the risk?", "competitive_probe": "If you could confidently show customers and prospects exactly how security is governed here, would that change conversations you're currently finding difficult?"}, "tree": {"start": {"type": "situation", "q": "How does security get managed day to day — is it just the tools you have, or is there someone actively steering it?", "options": [{"label": "We've tools in place — firewall, antivirus, backups — but no one really steering the overall picture", "next": "tools_probe"}, {"label": "We've had a security incident or scare and had to figure out the response as we went", "next": "incident_probe"}, {"label": "Nobody in the business has real security leadership — it's whoever's free at the time", "next": "noleader_probe"}, {"label": "A customer, insurer or regulation is starting to ask us questions we can't easily answer", "next": "compliance_probe"}, {"label": "We want to be able to demonstrate our security credentials — to win business, reassure customers, or stand out from competitors", "next": "competitive_probe"}]}, "tools_probe": {"type": "problem", "q": "Is there someone who owns the overall security picture — setting priorities, reviewing risk, making the calls — or does it stop at the tools themselves?", "options": [{"label": "There's some oversight, but it's informal and reactive", "next": "result_mid_tools_gov"}, {"label": "Honestly, it stops at the tools — nobody owns the bigger picture", "next": "result_hot_tools_noplan"}, {"label": "Yes, someone actively governs it and reviews risk regularly", "next": "result_none_governed"}]}, "incident_probe": {"type": "problem", "q": "When that happened, was there a documented plan to follow, or was the response worked out on the spot?", "options": [{"label": "No plan — entirely improvised in the moment", "next": "result_hot_incident_noplan"}, {"label": "Something informal existed, but it wasn't really followed properly", "next": "result_mid_incident_informal"}, {"label": "We haven't actually had a real incident, just a scare", "next": "result_warm_noincident"}]}, "noleader_probe": {"type": "problem", "q": "As the business has grown, has that gap in ownership stayed about the same, or is it becoming more noticeable?", "options": [{"label": "It's becoming more noticeable as we grow", "next": "result_hot_noleader_growing"}, {"label": "It's whoever's around at the time — no real pattern", "next": "result_mid_noleader_adhoc"}, {"label": "We're fairly confident in how it's handled today", "next": "result_dev_noleader_confident"}]}, "compliance_probe": {"type": "problem", "q": "Is that pressure tied to a specific deal, contract or renewal, or is it becoming a more general expectation?", "options": [{"label": "It's tied to a specific deal or contract we don't want to lose", "next": "result_hot_compliance_pressure"}, {"label": "Not sure we could produce what's actually being asked for", "next": "result_mid_compliance_unsure"}, {"label": "We already have something in place that covers this", "next": "result_none_compliance_covered"}]}, "result_mid_tools_gov": {"result": true, "level": "developing", "title": "Informal, Reactive Oversight", "body": "Some oversight exists but it's reactive rather than structured — governance that only shows up after something's already gone wrong.", "points": ["Ask what triggered oversight the last time it happened", "Position structured, ongoing governance rather than reactive attention"], "next": "Nurture — position proactive governance as the next step up."}, "result_hot_tools_noplan": {"result": true, "level": "qualified", "title": "Tools Without Governance", "body": "Security tools with nobody steering the overall picture is one of the most common and least visible gaps — the tools give a false sense of coverage.", "points": ["Ask who would make the call if two tools gave conflicting signals", "Position leadership and governance as completing what the tools already do"], "next": "Strong opportunity — the gap is real even though it doesn't feel urgent day to day."}, "result_none_governed": {"result": true, "level": "none", "title": "No Immediate Opportunity", "body": "Genuine, active governance already in place — healthy today.", "points": ["Confirm how that governance is resourced, for future reference"], "next": "Park — revisit if the person doing this role ever changes."}, "result_hot_incident_noplan": {"result": true, "level": "qualified", "title": "Incident Handled With No Plan", "body": "Improvising a response to a real incident is high-risk and usually more costly and slower than it needed to be — a strong, concrete trigger.", "points": ["Ask how much longer the response took without a plan to follow", "Position a documented, tested incident response plan as preventing a repeat"], "next": "Urgent opportunity — use the real incident directly to justify action."}, "result_mid_incident_informal": {"result": true, "level": "developing", "title": "Informal Plan, Not Followed", "body": "Something existed on paper but didn't hold up in practice — a plan that isn't tested is barely better than no plan.", "points": ["Ask specifically where the informal plan broke down", "Position regular testing and review as what turns a document into a real capability"], "next": "Nurture — position testing and review as the missing piece."}, "result_warm_noincident": {"result": true, "level": "developing", "title": "Scare But No Real Incident Yet", "body": "A scare without a full incident is a valuable, low-cost warning — the business hasn't paid the full price of being unprepared yet.", "points": ["Ask what the scare revealed about current readiness", "Use the scare as a preview, not a closed chapter"], "next": "Nurture — use the scare as the trigger before a real incident forces the issue."}, "result_hot_noleader_growing": {"result": true, "level": "qualified", "title": "Growing Business, No Security Leadership", "body": "A widening gap between business growth and security leadership is a strong, time-sensitive opportunity — the risk compounds as the business scales.", "points": ["Ask what's changed in the business that makes this more pressing now", "Position senior security leadership as scaling alongside the business, not behind it"], "next": "Strong, time-bound opportunity — growth itself is the trigger."}, "result_mid_noleader_adhoc": {"result": true, "level": "developing", "title": "Ad Hoc Ownership", "body": "Whoever's free making security calls is a fragile model — works until the wrong moment, then doesn't.", "points": ["Ask what happens when nobody's available to make the call", "Position clear, consistent ownership as removing the fragility"], "next": "Nurture — highlight the risk of decisions depending on availability, not expertise."}, "result_dev_noleader_confident": {"result": true, "level": "developing", "title": "Confident, But Unverified", "body": "Confidence without a recent independent review is exactly the kind of gap that only becomes visible after something goes wrong.", "points": ["Ask when the current approach was last independently reviewed", "Offer a light-touch review to confirm the confidence is well-founded"], "next": "Nurture — offer a review to validate or challenge existing confidence."}, "result_hot_compliance_pressure": {"result": true, "level": "qualified", "title": "Deal-Driven Compliance Pressure", "body": "Pressure tied to a specific deal or contract creates real urgency — and a very concrete reason to act now rather than eventually.", "points": ["Confirm exactly what's being asked for and by when", "Position a fast, structured governance package to meet the specific requirement"], "next": "Urgent, deal-driven opportunity — there's a real deadline to work against."}, "result_mid_compliance_unsure": {"result": true, "level": "developing", "title": "Uncertain Evidence Readiness", "body": "Not being sure you could produce evidence of governance is itself a gap worth closing before it's tested by someone outside the business.", "points": ["Ask exactly what's likely to be asked for, and by whom", "Offer to help build the evidence base before it's needed under pressure"], "next": "Nurture — get ahead of the ask before an external party forces the timeline."}, "result_none_compliance_covered": {"result": true, "level": "none", "title": "Already Covered", "body": "Something's already in place that addresses this — worth confirming it's still current.", "points": ["Confirm when that was last reviewed or updated"], "next": "Park — revisit at next renewal or review cycle."}, "competitive_probe": {"type": "problem", "q": "Is that mainly about winning new business, reassuring existing customers, or getting ahead of competitors who are already doing this?", "options": [{"label": "Winning new business — we keep getting asked before contracts are signed", "next": "result_hot_competitive_newbiz"}, {"label": "Reassuring existing customers who are starting to ask more questions", "next": "result_dev_competitive_reassure"}, {"label": "Getting ahead of competitors — we know some of them already have this", "next": "result_dev_competitive_ahead"}]}, "result_hot_competitive_newbiz": {"result": true, "level": "qualified", "title": "Security as a Deal-Winning Differentiator", "body": "Being asked for security credentials before contracts close means this directly affects revenue, not just risk — a strong, commercially-driven reason to act.", "points": ["Ask how many deals have stalled or been asked about this recently", "Position a clear, presentable security and governance story as a sales enabler, not just a defensive measure"], "next": "Strong, commercially-driven opportunity — frame this as revenue protection, not just risk reduction."}, "result_dev_competitive_reassure": {"result": true, "level": "developing", "title": "Reassuring an Increasingly Curious Customer Base", "body": "Customers asking more questions is an early signal, not yet a crisis — a good moment to get ahead of it before it becomes a blocker.", "points": ["Ask what prompted customers to start asking", "Offer a clear, simple way to answer those questions confidently"], "next": "Nurture — get ahead of rising customer expectations before they become a blocker."}, "result_dev_competitive_ahead": {"result": true, "level": "developing", "title": "Competitive Catch-Up", "body": "Knowing competitors already have this is a good motivator, but without a specific deal or customer driving it, the urgency is more strategic than immediate.", "points": ["Ask which competitors, and how they know", "Position this as a strategic differentiator to get ahead of, not just match"], "next": "Nurture — position as getting ahead, not just catching up."}}, "situationFollowUp": {"q": "How long has security been handled this way, and is anything changing — new customers, a new regulation, growth that's stretching things?", "options": [{"label": "Been like this for a long time, no changes", "note": "Long-standing approach to security, no near-term change."}, {"label": "Things are changing — new customers, regulation, growth", "note": "Change is coming that raises the stakes on this gap."}]}, "implicationFollowUp": {"q": "Does this reach beyond what you've said — customer trust, contracts, or how the business would be perceived if it became public?", "options": [{"label": "Yes, it goes wider than that", "note": "The impact reaches into trust, contracts or public perception."}, {"label": "No, that's really the whole picture", "note": "The impact stays contained to what's already been discussed."}]}}, {"id": "mobile-office", "name": "Mobile Office", "short": "Mobile Office", "icon": "💼", "color": "#4A3653", "blurb": "The hybrid‑worker bundle — anywhere working, secured.", "criteria": ["Hybrid or remote staff struggling with access or security", "Field staff on unsecured connections to company data", "No managed security layer for out‑of‑office working"], "implicationQuestions": {"result_dev_lowneed": "When that change lands, what would it cost the business to not have the right setup already in place?", "result_mid_lowneed": "What would need to happen for that to go from possibly to something real?", "result_none_lowneed": "Is there anything on the horizon — growth, a new site — that could change that?", "result_hot_security": "What does that friction actually cost — time lost, workarounds, or risk you're carrying?", "result_mid_struggle": "Of all of that, which one thing would make the biggest difference if it just worked?", "result_hot_productivity": "How much time would you say gets lost each week just trying to stay in touch or get to the right system?", "result_dev_working": "If one of those remote devices were lost or compromised tomorrow, what would it expose?", "result_mid_working": "For whatever's not covered, what's the realistic worst case if a device without it went missing?", "result_none_working": "Good to hear — is that something you review periodically, or was it set up once and left alone?", "result_hot_field": "If a field device on an open network got compromised, what could someone reach from there?", "result_mid_field": "For the ones who don't have it yet, what are they typically accessing on the go?", "result_none_field": "Good — is that consistent for every field-based person, including anyone new who joins?"}, "needPayoff": {"lowneed_probe": "If the foundation was already in place before that change hits, would that make the transition painless?", "struggle_probe": "If hybrid staff worked as smoothly as if they were in the office, what would that be worth?", "working_probe": "If that risk was closed off without disrupting how well things currently work, would that be worth doing?", "field_probe": "If field staff had the same secure access as the office, what would that be worth in peace of mind?"}, "tree": {"start": {"type": "situation", "q": "How much of the team works outside the office — field, hybrid, multiple sites — and how well does that actually work today?", "options": [{"label": "Mostly office‑based, hybrid isn't really a thing here", "next": "lowneed_probe"}, {"label": "We have hybrid or remote staff and it's a struggle", "next": "struggle_probe"}, {"label": "We have hybrid or remote staff and it mostly works", "next": "working_probe"}, {"label": "We have field staff, not just remote office work", "next": "field_probe"}]}, "lowneed_probe": {"type": "problem", "q": "Any plans to change that — new sites, more flexible working, or field‑based roles coming up?", "options": [{"label": "Yes, that's coming", "next": "result_dev_lowneed"}, {"label": "Possibly, nothing confirmed yet", "next": "result_mid_lowneed"}, {"label": "No, not really", "next": "result_none_lowneed"}]}, "struggle_probe": {"type": "problem", "q": "What's the biggest friction — access to files and systems, security, or just staying connected on calls or Teams?", "options": [{"label": "Security and access are the issue", "next": "result_hot_security"}, {"label": "A bit of everything — access, security and staying connected", "next": "result_mid_struggle"}, {"label": "Just staying connected, more of a productivity thing", "next": "result_hot_productivity"}]}, "working_probe": {"type": "problem", "q": "Good — is that backed by managed security like MFA, endpoint protection and VPN, or more informal?", "options": [{"label": "Fairly informal, no real security layer", "next": "result_dev_working"}, {"label": "Some of it — MFA yes, but not full endpoint protection", "next": "result_mid_working"}, {"label": "Yes, properly secured", "next": "result_none_working"}]}, "field_probe": {"type": "problem", "q": "How do field staff access company systems and data — a secure connection, or ad hoc, like personal hotspots or unsecured Wi‑Fi?", "options": [{"label": "Pretty ad hoc or unsecured", "next": "result_hot_field"}, {"label": "Some field staff have it, others don't", "next": "result_mid_field"}, {"label": "They have proper secure access", "next": "result_none_field"}]}, "result_dev_lowneed": {"result": true, "level": "developing", "title": "Emerging Opportunity — Future Need Identified", "body": "No current need, but change is coming — worth planting the seed now.", "points": ["Ask for a rough timeline on the change", "Offer to revisit closer to the date"], "next": "Nurture — flag for follow‑up nearer the change."}, "result_none_lowneed": {"result": true, "level": "none", "title": "No Immediate Opportunity", "body": "Office‑based model with no change on the horizon.", "points": ["Note for future reference"], "next": "Park — low priority today."}, "result_mid_lowneed": {"result": true, "level": "surface", "title": "Possible, Unconfirmed Change", "body": "Nothing concrete yet, but worth a light touchpoint rather than writing it off entirely.", "points": ["Ask what would need to happen for it to become concrete", "Set a light future check‑in rather than a hard follow‑up"], "next": "Very light nurture — check in occasionally, don't push."}, "result_hot_security": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Hybrid Security Gap", "body": "Struggling hybrid workers with security and access friction is a strong, felt pain affecting both productivity and risk.", "points": ["Quantify the productivity impact — time lost, workarounds used", "Position the Mobile Office bundle — MFA, endpoint backup, managed security"], "next": "Strong opportunity — lead with the security and access fix together."}, "result_hot_productivity": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Connectivity Gap", "body": "Hybrid staff struggling to stay connected is a direct productivity cost, easy to quantify.", "points": ["Ask how staff currently reach the office — VPN, nothing, workarounds?", "Position a hosted softphone plus M365 as the connected‑anywhere fix"], "next": "Strong opportunity — quantify lost productivity and propose the bundle."}, "result_mid_struggle": {"result": true, "level": "qualified", "title": "Multiple Compounding Frictions", "body": "When several frictions compound together, the combined impact is usually bigger than any one issue alone — a strong case for a complete fix.", "points": ["Ask which friction hurts the most day to day", "Position the full Mobile Office bundle rather than a single‑point fix"], "next": "Strong opportunity — the combination of issues justifies a complete solution."}, "result_dev_working": {"result": true, "level": "developing", "title": "Emerging Opportunity — Informal Security", "body": "Working today, but without a real security layer — a silent risk.", "points": ["Ask what would happen if a remote device were lost or compromised", "Introduce managed security as protecting what already works"], "next": "Nurture — position as protecting current productivity, not fixing a break."}, "result_none_working": {"result": true, "level": "none", "title": "No Immediate Opportunity", "body": "Hybrid working is functional and secured.", "points": ["Confirm headcount trend for future reference"], "next": "Park — revisit if headcount or hybrid ratio grows."}, "result_mid_working": {"result": true, "level": "developing", "title": "Partial Security Layer", "body": "Partial security is common but leaves specific, identifiable gaps that are usually straightforward to close.", "points": ["Ask specifically what's missing — endpoint protection, VPN, backup?", "Position it as completing an already‑good foundation"], "next": "Upsell — close the specific identified gap."}, "result_hot_field": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Field Staff Security Gap", "body": "Field staff on unsecured connections accessing company data is a real, fixable risk.", "points": ["Ask what data field staff access — customer, financial, operational", "Position secure mobile access plus managed devices as the fix"], "next": "Strong opportunity — lead with the data exposure risk."}, "result_none_field": {"result": true, "level": "none", "title": "No Immediate Opportunity", "body": "Field access is already properly secured.", "points": ["Confirm setup for future reference"], "next": "Park — low priority today."}, "result_mid_field": {"result": true, "level": "developing", "title": "Inconsistent Field Coverage", "body": "Inconsistent coverage usually means the riskiest staff — often the newest or most mobile — are the least protected.", "points": ["Ask which field staff are covered and which aren't", "Standardise coverage across the whole field team"], "next": "Nurture — a consistency gap is often an easy, logical extension."}}, "situationFollowUp": {"q": "How long has hybrid or remote working been set up this way, and is anything changing — more remote hires, new sites, more travel?", "options": [{"label": "Been like this for a while, nothing changing", "note": "Stable hybrid setup, no near-term change."}, {"label": "Something's changing soon", "note": "A change is coming that's a natural trigger to revisit this."}]}, "implicationFollowUp": {"q": "Does this reach beyond what you've mentioned — productivity across the wider team, security exposure, or customer-facing work?", "options": [{"label": "Yes, it touches other things too", "note": "The impact extends beyond the immediate issue."}, {"label": "No, that's the whole picture", "note": "The impact stays contained to what's already been discussed."}]}}, {"id": "managed-security", "name": "Managed Security", "short": "Managed Security", "icon": "🔒", "color": "#7FAF3C", "blurb": "SOC‑backed monitoring across endpoint, identity and firewall.", "criteria": ["No active threat monitoring — issues found only after impact", "Antivirus only, with no EDR or behavioural detection", "A prior incident with little or no change made since"], "implicationQuestions": {"result_hot_reactive": "By the time it breaks or locks up, how much damage could already be done — data taken, downtime, or both?", "result_mid_reactive": "In a day or two of unnoticed access, what could someone actually do?", "result_warm_reactive": "How quickly is 'fairly quickly', realistically — hours, or could it be days?", "result_hot_partial": "What kind of threat would get through antivirus but wouldn't get caught by something more modern?", "result_mid_partial": "If it turned out that bundled protection was lighter than you thought, would that be worth knowing?", "result_warm_partial": "If we found a gap in there, how would that change how you feel about it?", "result_dev_healthy": "If a compromised login or a firewall alert went unnoticed because it's not part of the same picture, what could that lead to?", "result_mid_healthy": "If a firewall alert went off right now, who would actually see it?", "result_hot_incident": "If that exact thing happened again tomorrow, what would it cost you this time round?", "result_mid_incident": "What's been competing for priority — and is this still worth bumping up the list?", "result_hot_incident_partial": "For whatever's still not covered, is that the same gap that caused the original incident, or something different?", "result_none_healthy": "Good — is that reviewed against new threat types regularly, or was it set up once and left running?"}, "needPayoff": {"reactive_probe": "If you had eyes on this 24/7 instead of finding out after the fact, what would that change?", "partial_probe": "If EDR sat on top of what you already have, would that close the gap without a big disruption?", "healthy_probe": "If identity and firewall were pulled into the same picture as your endpoints, would that complete it?", "incident_probe": "If we made sure that specific gap couldn't be exploited again, how much would that be worth?"}, "tree": {"start": {"type": "situation", "q": "How do you currently find out if something suspicious is happening on your network or systems — is anyone actively monitoring, or would you only find out after the fact?", "options": [{"label": "We'd only find out after something went wrong", "next": "reactive_probe"}, {"label": "We have some monitoring or antivirus but nothing 24/7", "next": "partial_probe"}, {"label": "We have proper 24/7 monitoring already", "next": "healthy_probe"}, {"label": "We've had a security incident before", "next": "incident_probe"}]}, "reactive_probe": {"type": "problem", "q": "How would that discovery actually happen — a customer complaint, a locked‑out system, something else?", "options": [{"label": "Realistically, when something breaks or locks up", "next": "result_hot_reactive"}, {"label": "Somewhere in between — we'd probably notice within a day or two", "next": "result_mid_reactive"}, {"label": "We'd probably notice fairly quickly some other way", "next": "result_warm_reactive"}]}, "partial_probe": {"type": "problem", "q": "Does that cover endpoint detection and response, or is it more traditional antivirus?", "options": [{"label": "Traditional antivirus only, no EDR", "next": "result_hot_partial"}, {"label": "Not sure — it came bundled with something else", "next": "result_mid_partial"}, {"label": "Not sure what level of protection it really is", "next": "result_warm_partial"}]}, "healthy_probe": {"type": "problem", "q": "Great — does that also cover identity risk, like risky M365 sign‑ins, and firewall alert correlation, or just endpoints?", "options": [{"label": "Just endpoints, not identity or firewall", "next": "result_dev_healthy"}, {"label": "Identity yes, but not firewall correlation", "next": "result_mid_healthy"}, {"label": "Yes, fully integrated across the board", "next": "result_none_healthy"}]}, "incident_probe": {"type": "problem", "q": "What was the root cause, and what's changed in your monitoring since then?", "options": [{"label": "Not much has changed since the incident", "next": "result_hot_incident"}, {"label": "We meant to review it properly but it kept getting deprioritised", "next": "result_mid_incident"}, {"label": "We improved some things but it's patchy", "next": "result_hot_incident_partial"}]}, "result_hot_reactive": {"result": true, "level": "qualified", "title": "Qualified Opportunity — No Active Monitoring", "body": "Finding out only after something breaks is a high‑risk, high‑urgency gap — easy to build a case around.", "points": ["Walk through the cost and impact of a realistic incident going undetected", "Position 24/7 SOC‑backed monitoring as closing the detection gap"], "next": "Urgent — this is a foundational gap, propose SOC monitoring directly."}, "result_warm_reactive": {"result": true, "level": "developing", "title": "Emerging Opportunity — Some Informal Detection", "body": "Some visibility exists informally, but it's not systematic — needs quantifying.", "points": ["Ask how long that informal detection usually takes", "Reframe time‑to‑detect as the real risk"], "next": "Nurture — quantify the detection gap to build urgency."}, "result_mid_reactive": {"result": true, "level": "developing", "title": "Delayed Detection", "body": "A day or two of dwell time is still a long window for an attacker to do damage — much better than nothing, but far from real‑time.", "points": ["Ask what a day or two of unnoticed access could actually lead to", "Frame 24/7 monitoring as closing that specific window"], "next": "Nurture — quantify what could happen in that detection window."}, "result_hot_partial": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Antivirus‑Only Gap", "body": "Traditional AV without EDR misses modern threats — a clear capability gap to close.", "points": ["Explain the difference between AV and EDR — behavioural detection", "Position EDR as an upgrade path, not a rip‑and‑replace"], "next": "Strong opportunity — position EDR as a natural upgrade."}, "result_warm_partial": {"result": true, "level": "developing", "title": "Emerging Opportunity — Unclear Coverage", "body": "Uncertainty about the current protection level is itself a discovery opportunity.", "points": ["Offer a quick security posture review", "Use the findings to shape the proposal"], "next": "Nurture — offer a security posture review to clarify the gap."}, "result_mid_partial": {"result": true, "level": "surface", "title": "Unknown Bundled Protection", "body": "Bundled security tools are often under‑configured or lower‑tier than they appear — worth a proper check.", "points": ["Offer to identify exactly what's included", "Use the finding either way as the basis for a recommendation"], "next": "Light nurture — clarify exactly what's actually protecting them."}, "result_dev_healthy": {"result": true, "level": "developing", "title": "Emerging Opportunity — Partial Coverage", "body": "Endpoint coverage exists, but identity and firewall visibility are missing pieces.", "points": ["Ask about visibility into M365 risky sign‑ins specifically", "Position identity and firewall visibility as closing the remaining gaps"], "next": "Upsell opportunity — extend existing coverage to identity and firewall."}, "result_none_healthy": {"result": true, "level": "none", "title": "No Immediate Opportunity", "body": "Comprehensive, integrated security monitoring already in place.", "points": ["Confirm provider and renewal date for competitive tracking"], "next": "Park — revisit at renewal or if incidents occur elsewhere in their sector."}, "result_mid_healthy": {"result": true, "level": "developing", "title": "Identity Covered, Firewall Gap", "body": "Partial integration still leaves blind spots — an alert on the firewall side could go unnoticed even with good identity coverage.", "points": ["Ask how firewall alerts get handled today, if at all", "Position firewall correlation as completing the picture"], "next": "Upsell — close the specific firewall visibility gap."}, "result_hot_incident": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Post‑Incident, No Change", "body": "A real incident with no real change since is a strong, urgent trigger.", "points": ["Use the incident directly to justify budget", "Position 24/7 monitoring as preventing a repeat"], "next": "Fast‑track — same‑quarter opportunity, lead with preventing a repeat."}, "result_hot_incident_partial": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Post‑Incident, Partial Fix", "body": "Improvements were made but coverage is still patchy — a strong opportunity to complete the picture.", "points": ["Ask specifically what's still not covered", "Position a full SOC‑backed layer to close remaining gaps"], "next": "Strong opportunity — identify and close the remaining gaps."}, "result_mid_incident": {"result": true, "level": "developing", "title": "Good Intentions, No Action", "body": "Intent without action after a real incident is a classic gap — they know it matters, they just haven't gotten to it.", "points": ["Ask what's been competing for priority", "Offer to make this the easy option rather than another big project"], "next": "Nurture — make action easier than continuing to defer it."}}, "situationFollowUp": {"q": "How long has monitoring been set up this way, and has anything changed recently — a new system, more staff, an incident elsewhere in your sector?", "options": [{"label": "Been like this for years, nothing's changed", "note": "Long-standing setup, no recent trigger event."}, {"label": "Something's changed or come up recently", "note": "A recent change or event is a natural trigger to revisit this."}]}, "implicationFollowUp": {"q": "Does this reach beyond what you've said — customer trust, compliance, or how long the business could operate if it happened?", "options": [{"label": "Yes, it goes wider than that", "note": "The impact reaches into trust, compliance or business continuity."}, {"label": "No, that's really the whole picture", "note": "The impact stays contained to what's already been discussed."}]}}, {"id": "eir-services", "name": "Connectivity & Access", "short": "Connectivity", "icon": "🌐", "color": "#C98A2C", "blurb": "Connectivity, carrier services, cloud infrastructure and project delivery.", "criteria": ["Connectivity actively disrupting the business", "No failover for a single‑line or single‑site setup", "Growth in sites or usage outpacing the current connectivity plan"], "implicationQuestions": {"result_hot_problem": "What does that actually cost you when it happens — lost trading time, frustrated staff, or both?", "result_mid_problem": "Is there a pattern to when it's bad — time of day, specific activities, anything like that?", "result_warm_problem": "Is it getting more noticeable as you add more people or systems onto it?", "result_dev_healthy": "If that single line went down for a full day, what would that actually cost the business?", "result_mid_healthy": "How long does that manual switch typically take once someone notices?", "result_hot_growth": "If connectivity wasn't ready in time for that growth, what would it hold back?", "result_mid_growth": "Who else is involved in that discussion, and what's the timeline looking like?", "result_warm_growth": "Is that new site likely to need the same setup as the others, or something different?", "result_warm_unknown": "If that review turned up you were overpaying or underpowered, what would you want to do about it?", "result_mid_unknown": "Fair enough — would a plain factual summary, no follow-up required, be a fairer way to look at it?", "result_none_unknown": "Is there a renewal or a change coming up that would make this worth another look?", "result_none_healthy": "Good — is there a renewal coming up where it'd be worth checking the failover is still fit for how the business has grown?"}, "needPayoff": {"problem_probe": "If connectivity just worked, reliably, what would that be worth to how the business runs day to day?", "healthy_probe": "If failover meant you never noticed an outage at all, would that be worth the small extra cost?", "growth_probe": "If connectivity scaled smoothly alongside the growth, would that remove one thing to worry about?", "unknown_probe": "If we gave you full clarity on what you're paying for and what you actually need, would that help regardless?"}, "tree": {"start": {"type": "situation", "q": "How's your current internet connectivity — reliable enough for everything the business needs, or does it cause problems?", "options": [{"label": "Real problems — slow, drops out, not enough bandwidth", "next": "problem_probe"}, {"label": "It's fine most of the time", "next": "healthy_probe"}, {"label": "We're growing or opening new sites, not sure our plan is right", "next": "growth_probe"}, {"label": "Not sure what we're even on", "next": "unknown_probe"}]}, "problem_probe": {"type": "problem", "q": "What's the actual impact — slow systems, dropped calls, can't work at all during outages?", "options": [{"label": "Real business impact — can't work properly", "next": "result_hot_problem"}, {"label": "It's inconsistent — fine some days, bad on others", "next": "result_mid_problem"}, {"label": "Annoying but not critical", "next": "result_warm_problem"}]}, "healthy_probe": {"type": "problem", "q": "Is there any failover if the main line goes down, or would you be offline until it's fixed?", "options": [{"label": "No failover — we'd be offline", "next": "result_dev_healthy"}, {"label": "We have a backup plan but it's manual, not automatic", "next": "result_mid_healthy"}, {"label": "Yes, we have failover", "next": "result_none_healthy"}]}, "growth_probe": {"type": "problem", "q": "How many sites are we talking, and what's driving the growth — new locations, more staff, more cloud usage?", "options": [{"label": "Multiple new sites or a big jump in usage", "next": "result_hot_growth"}, {"label": "Not fully decided yet, but it's being discussed", "next": "result_mid_growth"}, {"label": "Just one more site, fairly modest change", "next": "result_warm_growth"}]}, "unknown_probe": {"type": "problem", "q": "Would it help if I pulled together a quick connectivity review — current speed, contract terms and options?", "options": [{"label": "Yes, that would help", "next": "result_warm_unknown"}, {"label": "Possibly — I just don't want a sales pitch", "next": "result_mid_unknown"}, {"label": "Not a priority right now", "next": "result_none_unknown"}]}, "result_hot_problem": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Connectivity Pain", "body": "Connectivity actively disrupting the business is a strong, easy‑to‑justify pain.", "points": ["Quantify downtime cost — lost trading time, staff idle", "Position Fibre/DIA with firewall failover as the fix"], "next": "Strong opportunity — quantify the pain and propose a resilient connectivity upgrade."}, "result_warm_problem": {"result": true, "level": "developing", "title": "Emerging Opportunity — Minor Connectivity Friction", "body": "Not critical yet, but worth tracking as usage grows.", "points": ["Ask if bandwidth needs are growing — cloud apps, video, backup", "Position as future‑proofing rather than an urgent fix"], "next": "Nurture — revisit as bandwidth demands grow."}, "result_mid_problem": {"result": true, "level": "developing", "title": "Inconsistent Performance", "body": "Inconsistency is often harder to diagnose than a constant problem, and it erodes confidence in the connection over time.", "points": ["Ask if there's a pattern — time of day, specific activities", "An inconsistent line often points to a capacity or contention issue"], "next": "Nurture — investigate the pattern before proposing a fix."}, "result_dev_healthy": {"result": true, "level": "developing", "title": "Emerging Opportunity — No Failover", "body": "Fine day‑to‑day, but a single point of failure is a real exposure.", "points": ["Ask what a full outage would cost per hour", "Introduce 4G/5G failover as low‑cost insurance"], "next": "Low‑friction upsell — position failover as cheap insurance."}, "result_none_healthy": {"result": true, "level": "none", "title": "No Immediate Opportunity", "body": "Reliable connectivity with failover already in place.", "points": ["Confirm contract end date for future reference"], "next": "Park — revisit at contract renewal."}, "result_mid_healthy": {"result": true, "level": "developing", "title": "Manual Failover Only", "body": "Manual failover still means downtime while someone notices and switches over — automatic failover closes that gap.", "points": ["Ask how long the manual switch typically takes", "Position automatic failover as removing the manual delay"], "next": "Upsell — automate what's currently a manual workaround."}, "result_hot_growth": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Growth‑Driven Need", "body": "Significant growth creates a natural, time‑bound connectivity conversation.", "points": ["Map out sites and timelines", "Position cloud infrastructure plus connectivity as scaling with them"], "next": "Strong, time‑bound opportunity — propose a phased connectivity plan for growth."}, "result_warm_growth": {"result": true, "level": "developing", "title": "Emerging Opportunity — Modest Growth", "body": "Some change coming, but not enough to force urgency yet.", "points": ["Get a rough timeline", "Check in closer to the actual move or expansion"], "next": "Nurture — follow up closer to the change."}, "result_mid_growth": {"result": true, "level": "developing", "title": "Growth Under Discussion", "body": "Early‑stage growth planning is a good time to get connectivity right before decisions are locked in elsewhere.", "points": ["Ask who else is involved in the growth planning", "Offer to be part of the planning conversation early"], "next": "Nurture — get involved early, before the growth plan is finalised."}, "result_warm_unknown": {"result": true, "level": "developing", "title": "Emerging Opportunity — Needs Discovery", "body": "No clear picture of current connectivity — a natural audit entry point.", "points": ["Ask for a copy of the current bill or contract", "Use the review to open the wider infrastructure conversation"], "next": "Book a connectivity review as the next step."}, "result_none_unknown": {"result": true, "level": "none", "title": "Follow‑Up Required", "body": "Not a current priority.", "points": ["Set a follow‑up trigger"], "next": "Log as a future follow‑up."}, "result_mid_unknown": {"result": true, "level": "surface", "title": "Cautious But Open", "body": "A specific objection to being sold to — respect it directly and lead with value, not a pitch.", "points": ["Reassure this is a factual review, not a sales call", "Offer to share findings even if there's no follow‑up action"], "next": "Light nurture — lead with value, no strings attached."}}, "situationFollowUp": {"q": "How long has connectivity been set up this way, and is anything changing — growth, a new site, more cloud usage?", "options": [{"label": "Been like this for years, nothing changing", "note": "Long-standing connectivity setup, no near-term change."}, {"label": "Something's changing soon", "note": "A change is coming that's a natural trigger to revisit connectivity."}]}, "implicationFollowUp": {"q": "Does this reach beyond what you've mentioned — customer experience, staff productivity, or other systems relying on it?", "options": [{"label": "Yes, it touches other things too", "note": "The impact extends beyond the immediate connectivity issue."}, {"label": "No, that's really it", "note": "The impact stays contained to what's already been discussed."}]}}, {"id": "secure-access-edge", "name": "Secure Access Edge", "short": "Secure Access Edge", "icon": "🔑", "color": "#6B3E63", "blurb": "SASE, Zero Trust and secure web access, tiered by need.", "criteria": ["Remote workers with no zero‑trust or modern secure access", "Inconsistent security policy across multiple sites", "No visibility or control over cloud app / shadow IT usage"], "implicationQuestions": {"result_hot_remote": "If a remote worker's device were compromised right now, what could someone reach through that connection?", "result_mid_remote": "Do staff ever find workarounds because it's slow or awkward to use?", "result_warm_remote": "Does that cover every app they use, or just some of them?", "result_hot_branches": "If one site got compromised, how easily could that spread to the others given how different they are?", "result_mid_branches": "What's different about those particular sites — is there a reason they're the exception?", "result_warm_branches": "How do policy changes actually get rolled out today — one at a time, or all at once?", "result_hot_cloud": "If sensitive data ended up in an app nobody approved, how would you even find out?", "result_mid_cloud": "What other cloud tools do teams tend to reach for that wouldn't show up in that picture?", "result_warm_cloud": "What's the one blind spot that worries you most?", "result_dev_lowneed": "When that lands, what would it cost to not have the right access model already in place?", "result_mid_lowneed": "What would need to happen for it to go from a conversation to an actual plan?", "result_none_lowneed": "Is there anything that would change that — growth, a new hire working remotely, anything like that?"}, "needPayoff": {"remote_probe": "If every remote connection was verified and least‑privilege by default, would that close the gap?", "branches_probe": "If every site ran under the exact same policy from one place, would that remove the inconsistency risk?", "cloud_probe": "If you had full visibility and control over cloud app usage, would that be worth having today?", "lowneed_probe": "If the access model was already future‑proofed before that change lands, would that make it a non‑issue?"}, "tree": {"start": {"type": "situation", "q": "Do you have staff or branches connecting to company systems from outside a single, secured office — remote workers, multiple sites, cloud apps?", "options": [{"label": "Yes, remote workers with no real secure access layer", "next": "remote_probe"}, {"label": "Yes, multiple branches or sites", "next": "branches_probe"}, {"label": "We're heavy users of cloud apps like M365 and other SaaS tools", "next": "cloud_probe"}, {"label": "No, everyone works from one secured office", "next": "lowneed_probe"}]}, "remote_probe": {"type": "problem", "q": "How do they connect today — a traditional VPN, nothing at all, or something else?", "options": [{"label": "Nothing, or an old / basic VPN", "next": "result_hot_remote"}, {"label": "An old VPN that's clunky but technically works", "next": "result_mid_remote"}, {"label": "Some kind of modern secure access already", "next": "result_warm_remote"}]}, "branches_probe": {"type": "problem", "q": "How are those sites connected and secured — is policy consistent across all of them?", "options": [{"label": "Inconsistent — each site is a bit different", "next": "result_hot_branches"}, {"label": "Mostly consistent, with one or two exceptions", "next": "result_mid_branches"}, {"label": "Fairly consistent already", "next": "result_warm_branches"}]}, "cloud_probe": {"type": "problem", "q": "Do you have visibility into what cloud apps staff are actually using, and any control over risky ones — shadow IT?", "options": [{"label": "No visibility or control", "next": "result_hot_cloud"}, {"label": "Some visibility through M365, but not third‑party apps", "next": "result_mid_cloud"}, {"label": "Some visibility, not full control", "next": "result_warm_cloud"}]}, "lowneed_probe": {"type": "problem", "q": "Any plans to change that — new sites, remote hires, more cloud adoption?", "options": [{"label": "Yes, that's likely coming", "next": "result_dev_lowneed"}, {"label": "It's come up in conversation but nothing's planned", "next": "result_mid_lowneed"}, {"label": "No, not really", "next": "result_none_lowneed"}]}, "result_hot_remote": {"result": true, "level": "qualified", "title": "Qualified Opportunity — No Modern Secure Access", "body": "Remote workers with no zero‑trust layer is a significant, fixable exposure.", "points": ["Ask what data and systems remote workers can actually reach", "Position Tier 1/2 — ZTNA for remote workers — as the starting point"], "next": "Strong opportunity — start with Tier 1/2 ZTNA for remote workers."}, "result_warm_remote": {"result": true, "level": "developing", "title": "Emerging Opportunity — Partial Coverage", "body": "Some modern access already exists — worth checking how complete it really is.", "points": ["Ask if it covers all apps or just some", "Look for gaps to extend coverage"], "next": "Nurture — probe for coverage gaps to extend."}, "result_mid_remote": {"result": true, "level": "developing", "title": "Outdated But Functional VPN", "body": "A working‑but‑clunky VPN often means workarounds and shadow IT creep in — the risk is in what people do to avoid using it.", "points": ["Ask if staff ever avoid using it because it's slow or awkward", "Modern ZTNA usually improves both security and user experience"], "next": "Upsell — position modern access as solving usability, not just security."}, "result_hot_branches": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Inconsistent Branch Security", "body": "Inconsistent policy across sites is a real compliance and risk gap.", "points": ["Map out how many sites and what's different about each", "Position Tier 3 — full SASE/SSE — for consistent, centralised policy"], "next": "Strong opportunity — propose centralised policy via SASE/SSE."}, "result_warm_branches": {"result": true, "level": "developing", "title": "Emerging Opportunity — Mostly Consistent", "body": "Reasonably consistent already — a lighter opportunity around centralisation or visibility.", "points": ["Ask how policy changes get rolled out today", "Introduce centralised management as an efficiency gain"], "next": "Nurture — position as efficiency, not urgency."}, "result_mid_branches": {"result": true, "level": "developing", "title": "Mostly Consistent, Known Exceptions", "body": "Known exceptions are actually a good sign — they're aware of the gap, which makes it easier to close.", "points": ["Ask specifically which sites are the exceptions and why", "Frame it as tidying up a known issue, not a full overhaul"], "next": "Quick‑win opportunity — close the specific known exceptions."}, "result_hot_cloud": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Shadow IT / Cloud App Risk", "body": "No visibility or control over cloud app usage is a growing, real risk — data leakage and compliance exposure.", "points": ["Ask about any known incidents of data ending up in the wrong place", "Position CASB / cloud app visibility as the fix"], "next": "Strong opportunity — lead with visibility and control over cloud app usage."}, "result_warm_cloud": {"result": true, "level": "developing", "title": "Emerging Opportunity — Partial Visibility", "body": "Some visibility already exists — extend it to full control.", "points": ["Ask what's still a blind spot", "Position as extending existing tools, not replacing them"], "next": "Nurture — extend existing visibility to full control."}, "result_mid_cloud": {"result": true, "level": "developing", "title": "Partial Cloud Visibility", "body": "Native visibility from one platform rarely extends to every app staff actually use — the real risk often lives in the blind spot.", "points": ["Ask what other cloud tools teams use day to day", "Position full CASB visibility as extending what they already have"], "next": "Upsell — extend existing visibility to the full cloud app estate."}, "result_dev_lowneed": {"result": true, "level": "developing", "title": "Emerging Opportunity — Future Need", "body": "No current need, but change is coming.", "points": ["Get a rough timeline", "Flag for follow‑up nearer the change"], "next": "Nurture — revisit nearer the change."}, "result_none_lowneed": {"result": true, "level": "none", "title": "No Immediate Opportunity", "body": "Single‑site, fully office‑based — low priority for Secure Access Edge today.", "points": ["Note for future reference"], "next": "Park — low priority today."}, "result_mid_lowneed": {"result": true, "level": "surface", "title": "On the Radar, Not Planned", "body": "Early awareness without a plan — a light touchpoint now can position you well for when it does become concrete.", "points": ["Ask what would trigger it becoming a real plan", "Stay lightly in touch rather than pushing"], "next": "Very light nurture — stay visible for when it becomes concrete."}}, "situationFollowUp": {"q": "How long has remote or multi-site access been set up this way, and is anything changing — new sites, more remote staff, more cloud apps?", "options": [{"label": "Been like this for a while, nothing changing", "note": "Long-standing access setup, no near-term change."}, {"label": "Something's changing soon", "note": "A change is coming that's a natural trigger to revisit this."}]}, "implicationFollowUp": {"q": "Does this reach beyond what you've said — data across multiple sites, compliance, or trust if something were exposed?", "options": [{"label": "Yes, it goes wider than that", "note": "The impact extends beyond the immediate issue into compliance or trust."}, {"label": "No, that's really the whole picture", "note": "The impact stays contained to what's already been discussed."}]}}, {"id": "eir-support", "name": "Support & Service Management", "short": "Support", "icon": "🎧", "color": "#00996C", "blurb": "Service desk, ownership, reporting and escalation.", "criteria": ["No clear support process or ownership when things break", "No defined SLA or escalation path", "Internal team stretched thin trying to cover it all"], "implicationQuestions": {"result_hot_chaotic": "Across a year, what does that chaos actually add up to — in lost time, lost trade, or both?", "result_mid_chaotic": "What happens on the days the right person isn't around?", "result_warm_chaotic": "How much staff time would you guess goes into chasing things down each month?", "result_hot_slow": "What's the real cost of not knowing how long something will take to get fixed?", "result_mid_slow": "Which one — the resourcing or the process — causes you more grief day to day?", "result_warm_slow": "Is it getting more frequent as things get busier, or has it stayed about the same?", "result_dev_healthy": "How much time goes into just figuring out which provider to call for a given issue?", "result_mid_healthy": "What are those remaining separate items, and how much hassle do they cause?", "result_hot_internal": "If that internal capacity actually broke down, what would the business lose in the meantime?", "result_mid_internal": "What's the specific thing you're watching for that would tell you it's become a problem?", "result_warm_internal": "What would need to change for that to stop being sustainable?", "result_none_healthy": "Good — is that relationship reviewed periodically, or is it just working well by habit?"}, "needPayoff": {"chaotic_probe": "If there was one number to call with a guaranteed response, what would that be worth?", "slow_probe": "If every issue had a clear SLA and escalation path, would that remove the uncertainty?", "healthy_probe": "If everything ran through a single point of contact, would that be worth simplifying, even if support is already decent?", "internal_probe": "If your team got that time back for higher‑value work, what would that be worth to the business?"}, "tree": {"start": {"type": "situation", "q": "When something goes wrong today — network, phones, backup, anything — what actually happens? Who do you call, and how fast is it usually sorted?", "options": [{"label": "We don't have a clear support process — it's a bit chaotic", "next": "chaotic_probe"}, {"label": "We have support, but it's slow or inconsistent", "next": "slow_probe"}, {"label": "We have decent support already", "next": "healthy_probe"}, {"label": "We manage most things ourselves internally", "next": "internal_probe"}]}, "chaotic_probe": {"type": "problem", "q": "What's the impact when that happens — how long does it typically take to get sorted, and what does that cost the business?", "options": [{"label": "Takes a long time, real business impact", "next": "result_hot_chaotic"}, {"label": "It varies a lot depending on who's around to help", "next": "result_mid_chaotic"}, {"label": "Usually sorted eventually, just messy", "next": "result_warm_chaotic"}]}, "slow_probe": {"type": "problem", "q": "Is that a resourcing issue on their end, unclear escalation paths, or something else?", "options": [{"label": "Unclear escalation, no real SLA", "next": "result_hot_slow"}, {"label": "A bit of both, if I'm honest", "next": "result_mid_slow"}, {"label": "Just occasionally slow, not a big deal", "next": "result_warm_slow"}]}, "healthy_probe": {"type": "problem", "q": "Good — is that a single point of contact across everything, network, voice, backup, security, or different providers for different things?", "options": [{"label": "Different providers for different things", "next": "result_dev_healthy"}, {"label": "Mostly one contact, but a couple of things sit elsewhere", "next": "result_mid_healthy"}, {"label": "Yes, single point of contact for everything", "next": "result_none_healthy"}]}, "internal_probe": {"type": "problem", "q": "As you grow, is that still sustainable, or is it starting to stretch the team thin?", "options": [{"label": "Starting to stretch us thin", "next": "result_hot_internal"}, {"label": "Sustainable for now, but we're keeping an eye on it", "next": "result_mid_internal"}, {"label": "Still sustainable for now", "next": "result_warm_internal"}]}, "result_hot_chaotic": {"result": true, "level": "qualified", "title": "Qualified Opportunity — No Support Structure", "body": "No clear support process with real business impact is a strong, easy‑to‑justify opportunity.", "points": ["Quantify the cost of a typical incident — time, lost trade", "Position a single point of contact — one support route and agreed escalation path"], "next": "Strong opportunity — lead with a defined support model and SLA."}, "result_warm_chaotic": {"result": true, "level": "developing", "title": "Emerging Opportunity — Messy but Functional", "body": "Gets resolved eventually — needs a cost story to create urgency.", "points": ["Ask how much staff time gets spent chasing issues", "Reframe the 'eventually' as a hidden cost"], "next": "Nurture — quantify the hidden cost of the messy process."}, "result_mid_chaotic": {"result": true, "level": "developing", "title": "Inconsistent, Person‑Dependent", "body": "Relying on specific people being available is a fragile setup — it works until the right person is unavailable.", "points": ["Ask what happens when that key person is out or unreachable", "Position a defined process as removing single points of failure"], "next": "Nurture — highlight the risk of depending on specific individuals."}, "result_hot_slow": {"result": true, "level": "qualified", "title": "Qualified Opportunity — No Clear SLA", "body": "Unclear escalation and no SLA is a real accountability gap.", "points": ["Ask what they'd want a proper SLA to guarantee", "Position agreed escalation paths and reporting as the fix"], "next": "Strong opportunity — propose a clear SLA and escalation model."}, "result_warm_slow": {"result": true, "level": "developing", "title": "Emerging Opportunity — Occasional Friction", "body": "Not painful enough yet to force a change.", "points": ["Ask if it's getting more frequent as they grow", "Keep warm for a future trigger"], "next": "Nurture — monitor for increasing frequency."}, "result_mid_slow": {"result": true, "level": "developing", "title": "Combined Resourcing and Process Gap", "body": "When both resourcing and process are weak, fixing just one won't fully solve it — worth addressing together.", "points": ["Ask which one causes more frustration day to day", "Position a managed model as solving both at once"], "next": "Strong nurture — a combined gap often justifies a combined fix."}, "result_dev_healthy": {"result": true, "level": "developing", "title": "Emerging Opportunity — Fragmented Support", "body": "Decent support, but split across multiple providers — a consolidation opportunity.", "points": ["Ask how many different providers or numbers they deal with", "Position a single point of contact as reducing complexity"], "next": "Upsell opportunity — position consolidation under one support model."}, "result_none_healthy": {"result": true, "level": "none", "title": "No Immediate Opportunity", "body": "Single point of contact and solid support already in place.", "points": ["Confirm satisfaction and contract terms for future reference"], "next": "Park — revisit at renewal."}, "result_mid_healthy": {"result": true, "level": "developing", "title": "Mostly Consolidated", "body": "Nearly there — a couple of stray relationships are usually easy to fold into a single model.", "points": ["Ask what those remaining separate items are", "Frame it as finishing the consolidation, not starting over"], "next": "Quick‑win opportunity — fold in the remaining stray relationships."}, "result_hot_internal": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Internal Team Stretched", "body": "An internal team being stretched thin as the business grows is a strong, relatable pain.", "points": ["Ask what's taking up the most internal time", "Position managed support as freeing up the internal team"], "next": "Strong opportunity — position as capacity relief for a stretched team."}, "result_warm_internal": {"result": true, "level": "developing", "title": "Emerging Opportunity — Sustainable For Now", "body": "No pressure yet, but growth will change that.", "points": ["Ask about growth plans or headcount trajectory", "Flag for follow‑up as they scale"], "next": "Nurture — revisit as they grow."}, "result_mid_internal": {"result": true, "level": "developing", "title": "Watching It Closely", "body": "Proactively watching for strain is a good sign — it means there's likely a clear trigger point you can plan around together.", "points": ["Ask what specifically they're watching for as a signal", "Offer to be the plan for when that signal appears"], "next": "Nurture — be the ready‑made plan for when the trigger hits."}}, "situationFollowUp": {"q": "How long has support been handled this way, and is anything changing — growth, new systems, a key person moving on?", "options": [{"label": "Been like this for years, nothing changing", "note": "Long-standing support setup, no near-term change."}, {"label": "Something's changing soon", "note": "A change is coming that's a natural trigger to revisit this."}]}, "implicationFollowUp": {"q": "Does this reach beyond what you've mentioned — customer experience, staff morale, or the wider team's ability to focus on their real jobs?", "options": [{"label": "Yes, it touches other things too", "note": "The impact extends beyond the immediate support issue."}, {"label": "No, that's really it", "note": "The impact stays contained to what's already been discussed."}]}}];
const PIECES = PIECES_A.concat(PIECES_B);
const PIECE_IDS = PIECES.map(p=>p.id);
const PIECE_BY_ID = {};
PIECES.forEach(p=>PIECE_BY_ID[p.id]=p);

const LEVEL_ORDER = ['none','surface','developing','qualified'];
const LEVELS = {
  none:       {label:'No Pain',   short:'—',        color:'#7A8394', bg:'#EEF0F2'},
  surface:    {label:'Surface',   short:'Surface',   color:'#B9791F', bg:'#FBF0DD'},
  developing: {label:'Emerging',  short:'Emerging',  color:'#2C6FB0', bg:'#E6F0FA'},
  qualified:  {label:'Qualified', short:'Qualified', color:'#00996C', bg:'#DFF7EC'}
};
const LEVEL_SCORE = {none:0, surface:1, developing:2, qualified:3};

/* ---- Shared closing guidance, keyed by final qualification level x how the
   customer responds to the Need-payoff question. Kept generic/reusable so we
   don't need hundreds of hand-written unique closing screens. ---- */
const CLOSE_TEMPLATES = {
  qualified:{
    positive:{ tag:'Ready to Move', ctaTier:'book_call', guidance:"They're bought into the value AND the pain is real — this is as good as discovery gets. Book a call with a specialist now to scope the solution and confirm decision-makers before momentum fades." },
    hesitant:{ tag:'Real Pain, Needs Reassurance', ctaTier:'book_call', guidance:"The pain is genuinely qualified, but something is holding them back from committing — cost, timing, trust, or another stakeholder needed. The fastest way through that is usually a short call with a specialist to answer their specific concern directly, rather than trying to resolve it yourself." }
  },
  developing:{
    positive:{ tag:'Warming Up', ctaTier:'book_call', guidance:"They like the sound of the fix even though the pain isn't fully proven yet. A short call with a specialist is a low-pressure way to go deeper — position it as exploring options, not proposing a solution." },
    hesitant:{ tag:'Early Stage, Low Urgency', ctaTier:'send_info', guidance:"Interest is lukewarm and the pain isn't sharp yet. Don't push for a call — send a short follow-up instead, log this clearly, and set a genuine trigger to revisit (renewal date, growth milestone, or a specific event)." }
  },
  surface:{
    positive:{ tag:'Curious But Unconfirmed', ctaTier:'send_info', guidance:"There's mild curiosity but nothing concrete underneath it yet. A light follow-up — a one-pager or short note — keeps the door open without overcommitting either side." },
    hesitant:{ tag:'Low Priority Today', ctaTier:'log_only', guidance:"Neither the pain nor the interest is strong enough to justify pushing further right now. Note it for the file and focus your remaining time on a more promising area." }
  },
  none:{
    positive:{ tag:'No Pain, Some Goodwill', ctaTier:'log_only', guidance:"There's no real problem here, but they're friendly to the conversation — a good sign for relationship-building even though there's nothing to close today." },
    hesitant:{ tag:'Not a Fit Today', ctaTier:'log_only', guidance:"No pain and no real interest — this area isn't worth further time in this conversation. Move on and revisit only if their circumstances change." }
  }
};

function buildCTA(piece, tier){
  if(tier==='book_call'){
    const subject = encodeURIComponent('Specialist call request — ' + piece.name);
    const body = encodeURIComponent(
      'Hi team,\n\nCould we get a ' + piece.short + ' specialist on a short call for a customer opportunity?\n\n' +
      'Area: ' + piece.name + '\n' +
      'Notes: [add customer name / account and opportunity detail here]\n\nThanks!'
    );
    return { label: '📅 Book a Call with a ' + piece.short + ' Specialist', href: 'mailto:?subject='+subject+'&body='+body };
  }
  if(tier==='send_info'){
    const subject = encodeURIComponent('Following up — ' + piece.name);
    const body = encodeURIComponent(
      'Hi,\n\nFollowing up with a bit more detail on ' + piece.name + ' for you to have a look through.\n\n' +
      '[Add specific detail or attach a one-pager]\n\nThanks!'
    );
    return { label: '✉️ Send Follow-Up Info', href: 'mailto:?subject='+subject+'&body='+body };
  }
  return null;
}

/* ---- Build the Implication + interactive Need-payoff layers onto every
   piece's tree. Situation -> Problem (3 options) -> Implication (2 options:
   high/low impact, tailored to the SPECIFIC problem answer just given) ->
   Need-payoff (2 options: positive/hesitant customer reaction) -> final
   Close screen with a concrete CTA (book a specialist call / send info /
   log only, depending on how qualified + how engaged they are). ---- */
function adjustLevel(level, impact){
  let idx = LEVEL_ORDER.indexOf(level);
  idx = impact==='high' ? Math.min(idx+1,3) : Math.max(idx-1,0);
  return LEVEL_ORDER[idx];
}
function transitionNote(fromLevel, toLevel, impact){
  if(toLevel===fromLevel){
    return impact==='high'
      ? "The impact holds this exactly where it was — now with real stakes confirmed behind it."
      : "The impact holds this at the same level — worth watching, but not enough alone to force urgency.";
  }
  const moved = LEVEL_ORDER.indexOf(toLevel) - LEVEL_ORDER.indexOf(fromLevel);
  return moved > 0
    ? "The implication answer actually strengthens this — the impact turned out bigger than the initial answer suggested."
    : "The implication answer softens this — the underlying issue is real, but the impact isn't significant enough yet to force urgency.";
}
function coreTitle(title){
  const idx = title.indexOf('—');
  if(idx!==-1) return title.slice(idx+1).trim();
  if(title==='No Immediate Opportunity') return 'Healthy — No Action Needed';
  if(title==='Follow-Up Required' || title==='Follow\u2011Up Required') return 'Needs Discovery';
  return title;
}
function buildTrees(){
  PIECES.forEach(piece=>{
    const newNodes = {};

    // ---- Situation layer: after the initial Situation answer, let the rep
    // choose to ask one more opening question before moving to Problem, or
    // skip straight to it. The follow-up's own answer doesn't change which
    // Problem question comes next — it only adds optional extra context —
    // so every branch still resolves to exactly the same set of outcomes. ----
    const startNode = piece.tree['start'];
    if(startNode && piece.situationFollowUp){
      startNode.options.forEach((opt, idx)=>{
        const originalNext = opt.next;
        const branchKey = 's' + idx;
        const choiceId = 'schoice_' + branchKey;
        const fuId = 'sfu_' + branchKey;
        newNodes[choiceId] = {
          type:'choice', stage:'situation',
          q:"Do you want to ask one more opening question to build a fuller picture, or move straight into it?",
          options:[
            {label:'Ask one more opening question', next: fuId},
            {label:'Move straight into the next question', next: originalNext}
          ]
        };
        newNodes[fuId] = {
          type:'situation',
          q: piece.situationFollowUp.q,
          options: piece.situationFollowUp.options.map(o=>({label:o.label, next: originalNext, note:o.note}))
        };
        opt.next = choiceId;
      });
    }

    // ---- Problem -> Implication (connected per-answer) ----
    Object.keys(piece.tree).forEach(nodeId=>{
      const node = piece.tree[nodeId];
      if(node.type !== 'problem') return;
      const npQuestion = piece.needPayoff[nodeId];
      node.options.forEach(opt=>{
        const baseId = opt.next;
        const base = piece.tree[baseId];
        if(!base || !base.result) return;
        // Implication question is looked up per SPECIFIC answer (baseId), not
        // shared across the whole problem node — connects directly to what
        // was just said rather than asking something generic.
        const qText = piece.implicationQuestions[baseId];
        const implId = 'impl_' + baseId;
        newNodes[implId] = {
          type:'implication',
          q: qText,
          options:[
            {label:'It adds up — real cost, time or risk', impact:'high', next: implId+'_hi'},
            {label:'Manageable — not a big deal', impact:'low', next: implId+'_lo'}
          ]
        };
        ['hi','lo'].forEach(tag=>{
          const impact = tag==='hi' ? 'high' : 'low';
          const finalLevel = adjustLevel(base.level, impact);
          const npId = implId + '_' + tag;

          // ---- Implication follow-up layer: same optional "ask one more"
          // pattern, inserted between the Implication answer and the
          // Need-payoff question. Purely additive context, doesn't change
          // the destination or the computed level. ----
          const ichoiceId = npId + '_ichoice';
          const ifuId = npId + '_ifu';
          if(piece.implicationFollowUp){
            newNodes[ichoiceId] = {
              type:'choice', stage:'implication',
              q:"Do you want to ask one more question about the impact, or move to the closing question?",
              options:[
                {label:'Ask one more impact question', next: ifuId},
                {label:'Move to the closing question', next: npId}
              ]
            };
            newNodes[ifuId] = {
              type:'implication',
              q: piece.implicationFollowUp.q,
              options: piece.implicationFollowUp.options.map(o=>({label:o.label, next: npId, note:o.note}))
            };
          }

          newNodes[npId] = {
            type:'needpayoff',
            q: npQuestion,
            options:[
              {label:'Positive — engages with it, sees the value', engagement:'positive', next: npId+'_pos'},
              {label:'Hesitant — non-committal or deflects', engagement:'hesitant', next: npId+'_hes'}
            ]
          };
          ['pos','hes'].forEach(etag=>{
            const engagement = etag==='pos' ? 'positive' : 'hesitant';
            const tmpl = CLOSE_TEMPLATES[finalLevel][engagement];
            newNodes[npId+'_'+etag] = {
              result:true,
              level:finalLevel,
              title: coreTitle(base.title) + ' — ' + tmpl.tag,
              body: base.body,
              transition: transitionNote(base.level, finalLevel, impact),
              points: base.points,
              next: base.next,
              closeGuidance: tmpl.guidance,
              cta: buildCTA(piece, tmpl.ctaTier)
            };
          });
        });
        opt.next = implId;
      });
    });
    Object.assign(piece.tree, newNodes);

    // Second pass: now that implId nodes exist in newNodes, point their hi/lo
    // options at the implication-choice node rather than directly at need-payoff.
    Object.keys(newNodes).forEach(id=>{
      const n = newNodes[id];
      if(n.type==='implication' && /^impl_/.test(id) && !/_ifu$/.test(id)){
        n.options.forEach(o=>{
          const ichoiceId = o.next + '_ichoice';
          if(piece.tree[ichoiceId]) o.next = ichoiceId;
        });
      }
    });
  });
}
buildTrees();


